export default function Mission() {
  return (
    <div className="py-24 text-center bg-white dark:bg-deepnavy-light">

      <h2 className="text-3xl font-bold mb-6 text-sapphire dark:text-babyblue">
        Our Mission
      </h2>

      <p className="max-w-3xl mx-auto text-sapphire/70 dark:text-periwinkle/80 text-lg leading-relaxed">
        We aim to simplify research understanding for everyone. ResearchMate uses AI
        and plain language explanations to help students and professionals easily
        understand complex research papers and extract meaningful insights.
      </p>

    </div>
  );
}
